import {KitsMultiSelect} from "../../../../form/selects";
import type {EditorEl} from "../Editor";

const MultiSelectEditor: EditorEl<{
  list:
    | {
        label: string;
        value: any;
      }[]
    | undefined;
}> = ({ list, ...options }) => {
  const listArray = Array.isArray(list) ? list : [];

  return (
    <KitsMultiSelect
      attached
      id={"editor-multiple"}
      withFilter
      value={options.value ?? undefined}
      list={listArray}
      filterBy={"label"}
      onChange={(e: any) => options.editorCallback && options.editorCallback(e.value)}
      inputSize="sm"
    />
  );
};

export default MultiSelectEditor;
